CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;
CREATE TABLE "FaceData" (
    "FaceDataID" integer GENERATED BY DEFAULT AS IDENTITY,
    "EmployeeID" integer NOT NULL,
    "OriginalImage" text NOT NULL,
    CONSTRAINT "PK_FaceData" PRIMARY KEY ("FaceDataID")
);

CREATE TABLE "Attendance" (
    "AttendanceID" integer GENERATED BY DEFAULT AS IDENTITY,
    "EmployeeID" integer NOT NULL,
    "AttendanceDate" date NOT NULL,
    "TimeIn" time,
    "TimeOut" time,
    "Status" character varying(20) NOT NULL,
    "LunchStartTime" time,
    "LunchEndTime" time,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
    "UpdatedAt" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
    CONSTRAINT "PK_Attendance" PRIMARY KEY ("AttendanceID")
);

CREATE TABLE "Departments" (
    "DepartmentID" integer GENERATED BY DEFAULT AS IDENTITY,
    "DepartmentName" character varying(100) NOT NULL,
    "Description" character varying(500) NOT NULL,
    "Performance" numeric(18,2) NOT NULL,
    "DateCreated" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
    "Budget" numeric(18,2) NOT NULL,
    "Status" character varying(50) NOT NULL DEFAULT 'Active',
    "ManagerID" integer,
    CONSTRAINT "PK_Departments" PRIMARY KEY ("DepartmentID")
);

CREATE TABLE "Employees" (
    "EmployeeID" integer GENERATED BY DEFAULT AS IDENTITY,
    "FirstName" character varying(100) NOT NULL,
    "LastName" character varying(100) NOT NULL,
    "Email" character varying(255),
    "PhoneNumber" character varying(20),
    "Address" character varying(500),
    "DateOfBirth" date NOT NULL,
    "Gender" character varying(10) NOT NULL,
    "DepartmentID" integer NOT NULL,
    "Position" character varying(100) NOT NULL,
    "Salary" numeric(18,2) NOT NULL,
    "DateHired" date NOT NULL,
    "EmploymentType" character varying(20) NOT NULL DEFAULT 'Full-time',
    "Status" character varying(50) NOT NULL DEFAULT 'Active',
    "ManagerID" integer,
    "IsManager" boolean NOT NULL,
    "FaceDataID" integer,
    "CreatedAt" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
    "UpdatedAt" timestamp without time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
    CONSTRAINT "PK_Employees" PRIMARY KEY ("EmployeeID"),
    CONSTRAINT "FK_Employees_Departments_DepartmentID" FOREIGN KEY ("DepartmentID") REFERENCES "Departments" ("DepartmentID") ON DELETE RESTRICT,
    CONSTRAINT "FK_Employees_Employees_ManagerID" FOREIGN KEY ("ManagerID") REFERENCES "Employees" ("EmployeeID"),
    CONSTRAINT "FK_Employees_FaceData_FaceDataID" FOREIGN KEY ("FaceDataID") REFERENCES "FaceData" ("FaceDataID")
);

CREATE TABLE "Loans" (
    "LoanID" integer GENERATED BY DEFAULT AS IDENTITY,
    "EmployeeID" integer NOT NULL,
    "LoanType" text NOT NULL,
    "LoanAmount" numeric(18,2) NOT NULL,
    "LoanStatus" text NOT NULL,
    "DateIssued" timestamp with time zone NOT NULL,
    "DueDate" timestamp with time zone NOT NULL,
    "PaidLoan" numeric(18,2) NOT NULL,
    "LoanTerm" numeric NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_Loans" PRIMARY KEY ("LoanID"),
    CONSTRAINT "FK_Loans_Employees_EmployeeID" FOREIGN KEY ("EmployeeID") REFERENCES "Employees" ("EmployeeID") ON DELETE CASCADE
);

CREATE TABLE "Logins" (
    "LoginID" integer GENERATED BY DEFAULT AS IDENTITY,
    "EmployeeID" integer NOT NULL,
    "Username" character varying(50) NOT NULL,
    "Password" character varying(255) NOT NULL,
    "LastLogin" timestamp without time zone,
    "FailedAttempts" integer NOT NULL DEFAULT 0,
    "IsLocked" boolean NOT NULL DEFAULT FALSE,
    "CreatedAt" timestamp with time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
    "UpdatedAt" timestamp with time zone NOT NULL DEFAULT (CURRENT_TIMESTAMP),
    CONSTRAINT "PK_Logins" PRIMARY KEY ("LoginID"),
    CONSTRAINT "FK_Logins_Employees_EmployeeID" FOREIGN KEY ("EmployeeID") REFERENCES "Employees" ("EmployeeID") ON DELETE CASCADE
);

CREATE INDEX "IX_Attendance_EmployeeID" ON "Attendance" ("EmployeeID");

