CREATE INDEX "IX_Employees_ManagerID" ON "Employees" ("ManagerID");

CREATE INDEX "IX_Loans_EmployeeID" ON "Loans" ("EmployeeID");

CREATE INDEX "IX_Logins_EmployeeID" ON "Logins" ("EmployeeID");

CREATE UNIQUE INDEX "IX_Logins_Username" ON "Logins" ("Username");

ALTER TABLE "Attendance" ADD CONSTRAINT "FK_Attendance_Employees_EmployeeID" FOREIGN KEY ("EmployeeID") REFERENCES "Employees" ("EmployeeID") ON DELETE CASCADE;

ALTER TABLE "Departments" ADD CONSTRAINT "FK_Departments_Employees_ManagerID" FOREIGN KEY ("ManagerID") REFERENCES "Employees" ("EmployeeID");

